def assess(record: dict) -> str:
    required = {"allowed_lateness", "case_id", "event_time", "watermark", "window_end"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = not (record["event_time"] > record["window_end"] or record["event_time"] < record["watermark"] - record["allowed_lateness"])
    return "PASS" if ok else "SIDE_OUTPUT_LATE_EVENT"

valid = {"case_id": "CASO-HYO-046-1A", **{"event_time":110,"window_end":120,"watermark":115,"allowed_lateness":10}}
if "case_id" not in valid:
    valid = {"case_id": "VALID", **valid}
invalid = dict(valid)
if "catalog_ok" in invalid:
    invalid["catalog_ok"] = not bool(invalid["catalog_ok"]) if invalid.get("catalog_ok") is True else False
elif "observed_ms" in invalid and "target_ms" in invalid:
    invalid["observed_ms"] = invalid["target_ms"] + 50
elif "means_fraud" in invalid:
    invalid["means_fraud"] = True
elif "cache_authoritative" in invalid:
    invalid["cache_authoritative"] = True
    invalid["transactions"] = "cache"
elif "holdout" in invalid:
    invalid["holdout"] = 0
elif "jobs" in invalid:
    invalid["jobs"] = 0
elif "baseline_frozen" in invalid:
    invalid["baseline_frozen"] = False
elif "auto_fraud" in invalid:
    invalid["auto_fraud"] = True
elif "stages" in invalid:
    try:
        invalid["stages"] = list(reversed(list(invalid["stages"])))
    except Exception:
        pass
else:
    for k, v in list(invalid.items()):
        if k == "case_id":
            continue
        if isinstance(v, bool):
            invalid[k] = not v
            break
        if isinstance(v, (int, float)):
            invalid[k] = -1 if v != -1 else 0
            break
incomplete = {k: v for k, v in valid.items() if k != "allowed_lateness"}
print(assess(valid), assess(invalid), assess(incomplete))

